INSERT INTO homepage_content (key, data) VALUES ('heroSlides', '[{"slug":"arya-federico","title":"Arya & Federico","location":"Lake Como, Italy","date":"June 2025","description":"When a supermodel married her Italian Stallion on a horse ranch outside Milan, it was so dreamy they had to have two weddings. Absolute goosebumps.","image":"https://cdn.prod.website-files.com/658138cfb5ff0b77ba94f1a6/68b95bf2db16a47758441157_AryaFed.jpeg","video":"https://player.vimeo.com/progressive_redirect/playback/1115761410/rendition/1080p/file.mp4?loc=external&log_user=0&signature=9975e843ca0874532925cddc3c17284392e82a52c045047b15a851487de76362"},{"slug":"priya-akshay","title":"Priya & Akshay","location":"Hyderabad, India","date":"December 2024","description":"Love is not about finding the perfect person, but about seeing perfection in the person you choose. Beautifully told by TFC Films & CO.","image":"https://cdn.prod.website-files.com/658138cfb5ff0b77ba94f1a6/68cd4796ad7681b7b12f4f1f_For%20website%20Images%20.png","video":"https://player.vimeo.com/progressive_redirect/playback/1120076645/rendition/1080p/file.mp4?loc=external&log_user=0&signature=7d187646a9f1d25c26670a514df3479973a025045bf6c87cfce832825579f926"},{"slug":"apoorva-kshitij","title":"Apoorva & Kshitij","location":"Uttarakhand","date":"March 2025","description":"An intimate, honest wedding filmed with a small crew, big hearts, and open skies. Somewhere between sunlight and song, magic happened.","image":"https://cdn.prod.website-files.com/658138cfb5ff0b77ba94f1a6/693a8aba3360a6accfb6d867_Website%20Main%20Cover%20Image%20-2.png","video":""},{"slug":"nikki-vishal","title":"Nikki & Vishal","location":"Mumbai, India","date":"March 2025","description":"The love we felt from our crew, friends, and family was overwhelming. Now we know what it truly means to have a TFC film — to feel it all over again.","image":"https://cdn.prod.website-files.com/658138cfb5ff0b77ba94f1a6/68762fb1fb6c30dddaefc218_W%20(15).webp","video":"https://player.vimeo.com/progressive_redirect/playback/1100541792/rendition/1080p/file.mp4?loc=external&log_user=0&signature=ffba76abf45ce393136bfff470e7c8d8420ecf180d516c94195371280264c516"}]'::jsonb) ON CONFLICT (key) DO UPDATE SET data=EXCLUDED.data;
