INSERT INTO homepage_content (key, data) VALUES ('aboutTeaser', '{"kicker":"Who We Are","title":"Real Films Made By","titleAccent":"Real Filmmakers","body":"TFC Films & CO. — Tales From the Culture — is not just a videography company. We are storytellers who bring the magic of cinema to life''s most precious moments, honouring tradition and culture in every frame.","images":{"main":"https://cdn.prod.website-files.com/658138cfb5ff0b77ba94f1a6/68cd4796ad7681b7b12f4f1f_For%20website%20Images%20.png","accent":"https://cdn.prod.website-files.com/658138cfb5ff0b77ba94f1a6/68b95bf2db16a47758441157_AryaFed.jpeg"},"stats":[{"value":"500+","label":"Films Created"},{"value":"35+","label":"Countries"},{"value":"12","label":"Awards Won"}],"ctaText":"Work With Us","ctaLink":"contact.html"}'::jsonb) ON CONFLICT (key) DO UPDATE SET data=EXCLUDED.data;
INSERT INTO homepage_content (key, data) VALUES ('chapters', '{"chapter1":{"title":"Where Every Love Story Becomes Magic","text":"Step into a world where cinema meets culture — and every celebration is framed like a fairytale."},"chapter2":{"title":"Unroll the Story","text":"Four enchanted scrolls — each revealing a chapter of who we are and what we create."},"chapter3":{"title":"A Kingdom of Stories","text":"Numbers that shimmer — each one a tale told, a culture honoured, a dream captured on film."},"chapter4":{"title":"Watch the Magic Unfold","text":"Fairytale films from across the world — scroll through our enchanted carousel of love stories."}}'::jsonb) ON CONFLICT (key) DO UPDATE SET data=EXCLUDED.data;